const source = $input.first().json;
const raw = source.output ?? source.text ?? '';

let parsed = null;

// 1. Prova parsing diretto JSON
try {
  const clean = String(raw)
    .replace(/```json\s*/gi, '')
    .replace(/```\s*/g, '')
    .trim();

  parsed = JSON.parse(clean);
} catch (e) {
  // 2. Prova a estrarre un JSON dal testo
  try {
    const clean = String(raw)
      .replace(/```json\s*/gi, '')
      .replace(/```\s*/g, '')
      .trim();

    const match = clean.match(/\{[\s\S]*\}/);
    if (match) {
      parsed = JSON.parse(match[0]);
    }
  } catch (e2) {
    parsed = null;
  }
}

// 3. Se non c'è JSON valido, prova lettura testuale
let categoria = null;
let codice_spedizione = null;

if (parsed && typeof parsed === 'object') {
  categoria = parsed.categoria ?? null;
  codice_spedizione = parsed.codice_spedizione ?? null;
} else {
  const lower = String(raw).toLowerCase();

  if (lower.includes('spedizione con codice')) {
    categoria = 'SPEDIZIONE_CON_CODICE';
  } else if (lower.includes('spedizione senza codice')) {
    categoria = 'SPEDIZIONE_SENZA_CODICE';
  } else if (lower.includes('qna') || lower.includes('q&a')) {
    categoria = 'QNA';
  }

  const codiceMatch = String(raw).match(/codice(?:_spedizione)?["':\s]*([A-Za-z0-9#\-_]+)/i);
  if (codiceMatch) {
    codice_spedizione = codiceMatch[1];
  }
}

// 4. Normalizzazione categoria
if (typeof categoria === 'string') {
  const normalized = categoria.trim().toLowerCase();

  if (normalized === 'spedizione_con_codice' || normalized === 'spedizione con codice') {
    categoria = 'SPEDIZIONE_CON_CODICE';
  } else if (normalized === 'spedizione_senza_codice' || normalized === 'spedizione senza codice') {
    categoria = 'SPEDIZIONE_SENZA_CODICE';
  } else if (normalized === 'qna' || normalized === 'q&a') {
    categoria = 'QNA';
  } else {
    categoria = 'QNA';
  }
} else {
  categoria = 'QNA';
}

return [{
  json: {
    categoria,
    codice_spedizione: codice_spedizione ?? null
  }
}];

